pub async fn sys_read(fd: usize, buf: UserCheck<[u8]>) -> KResult {
    if fd == 0 {
        trace!("read stdin, len = {}", buf.len());
    } else {
        debug!("read fd = {fd}, len = {}", buf.len());
    }

    let file = prepare_io::<true>(fd)?;
    let nread = file.read(buf).await?;
    Ok(nread as isize)
