//! 参考：<https://man7.org/linux/man-pages/man7/signal.7.html>
//!
//! signal action 是属于进程的，而线程可以有各自的掩码和待处理信号
//!
//! `fork` 会继承父进程的 signal action 和线程的掩码，但是线程的待处理信号会置空。
//!
//! 而 `execve` 会将 signal action 置为默认值（可能与 linux 不同），但是线程掩码和待处理信号保留

mod handlers;

use defines::signal::KSignalSet;
pub use handlers::{DefaultHandler, SignalHandlers};
use num_enum::TryFromPrimitive;

use crate::trap::TrapContext;

pub const SIG_ERR: usize = -1isize as usize;
pub const SIG_DFL: usize = 0;
pub const SIG_IGN: usize = 1;

pub struct SignalContext {
    pub old_mask: KSignalSet,
    pub old_trap_context: TrapContext,
}

#[derive(Debug, TryFromPrimitive)]
#[repr(usize)]
#[allow(non_camel_case_types)]
pub enum SigprocmaskHow {
    /// 掩蔽传入的信号集，即新掩码是传入值和旧的并集
    SIG_BLOCK = 0,
    /// 取消掩蔽传入的信号集
    SIG_UNBLOCK = 1,
    /// 将掩码设置为传入的信号集，即直接赋值
    SIG_SETMASK = 2,
}

use defines::signal::{KSignalAction, Signal, SIGSET_SIZE};

pub enum DefaultHandler {
    Terminate,
    Ignore,
    CoreDump,
    Stop,
    Continue,
}

impl DefaultHandler {
    pub fn new(signal: Signal) -> Self {
        #[allow(clippy::enum_glob_use)]
        use Signal::*;
        match signal {
            SIGABRT | SIGBUS | SIGILL | SIGQUIT | SIGSEGV | SIGSYS | SIGTRAP | SIGXCPU
            | SIGXFSZ => DefaultHandler::CoreDump,
            SIGCHLD | SIGURG | SIGWINCH => DefaultHandler::Ignore,
            SIGSTOP | SIGTSTP | SIGTTIN | SIGTTOU => DefaultHandler::Stop,
            SIGCONT => DefaultHandler::Continue,
            _ => DefaultHandler::Terminate,
        }
    }
}

/// 由进程持有
#[derive(Clone)]
pub struct SignalHandlers {
    actions: [KSignalAction; SIGSET_SIZE],
}

impl SignalHandlers {
    pub const fn new() -> Self {
        const DEFAULT_ACTION: KSignalAction = KSignalAction::new();
        Self {
            actions: [DEFAULT_ACTION; SIGSET_SIZE],
        }
    }

    pub fn action(&self, signal: Signal) -> &KSignalAction {
        &self.actions[signal as usize]
    }

    pub fn action_mut(&mut self, signal: Signal) -> &mut KSignalAction {
        &mut self.actions[signal as usize]
    }
}

