//! 做了一些简化

use core::cell::UnsafeCell;

use common::config::{PA_TO_VA, QEMU_PLIC_ADDR};

/// See §1.
const COUNT_SOURCE: usize = 1024;
/// See §1.
const COUNT_CONTEXT: usize = 15872;
const U32_BITS: usize = u32::BITS as _;

#[repr(transparent)]
struct Priorities([UnsafeCell<u32>; COUNT_SOURCE]);

#[repr(transparent)]
struct PendingBits([UnsafeCell<u32>; COUNT_SOURCE / U32_BITS]);

#[repr(transparent)]
struct Enables([UnsafeCell<u32>; COUNT_SOURCE * COUNT_CONTEXT / U32_BITS]);

#[repr(C, align(4096))]
struct ContextLocal {
    priority_threshold: UnsafeCell<u32>,
    claim_or_completion: UnsafeCell<u32>,
    _reserved: [u8; 4096 - 2 * core::mem::size_of::<u32>()],
}

/// The PLIC memory mapping.
///
/// See §3.
#[repr(C, align(4096))]
pub struct Plic {
    priorities: Priorities,
    pending_bits: PendingBits,
    _reserved0: [u8; 4096 - core::mem::size_of::<PendingBits>()],
    enables: Enables,
    _reserved1: [u8; 0xe000],
    context_local: [ContextLocal; COUNT_CONTEXT],
}

impl Plic {
    pub fn mmio() -> *mut Plic {
        const PLIC_VA: usize = PA_TO_VA + QEMU_PLIC_ADDR;
        #[allow(clippy::assertions_on_constants)]
        const {
            assert!(PLIC_VA % 4096 == 0);
        }
        PLIC_VA as *mut Plic
    }

    /// Sets priority for interrupt `source` to `value`.
    ///
    /// Write `0` to priority `value` effectively disables this interrupt
    /// `source`, for the priority value 0 is reserved for "never interrupt"
    /// by the PLIC specification.
    ///
    /// The lowest active priority is priority `1`. The maximum priority depends
    /// on PLIC implementation and can be detected with
    /// [`Plic::probe_priority_bits`].
    ///
    /// See §4.
    #[inline]
    pub fn set_priority(&self, source_id: usize, value: u32) {
        let ptr = self.priorities.0[source_id].get();
        unsafe { ptr.write_volatile(value) }
    }

    // /// Gets priority for interrupt `source`.
    // ///
    // /// See §4.
    // #[inline]
    // pub fn get_priority(&self, source_id: usize) -> u32 {
    //     let ptr = self.priorities.0[source_id].get();
    //     unsafe { ptr.read_volatile() }
    // }

    // /// Probe maximum level of priority for interrupt `source`.
    // ///
    // /// See §4.
    // #[inline]
    // pub fn probe_priority_bits(&self, source_id: usize) -> u32 {
    //     let ptr = self.priorities.0[source_id].get();
    //     unsafe {
    //         ptr.write_volatile(!0);
    //         ptr.read_volatile()
    //     }
    // }

    // /// Check if interrupt `source` is pending.
    // ///
    // /// See §5.
    // #[inline]
    // pub fn is_pending(&self, source_id: usize) -> bool {
    //     let group = source_id / U32_BITS;
    //     let index = source_id % U32_BITS;

    //     let ptr = self.pending_bits.0[group].get();
    //     (unsafe { ptr.read_volatile() } & (1 << index)) != 0
    // }

    /// Enable interrupt `source` in `context`.
    ///
    /// See §6.
    #[inline]
    pub fn enable(&self, source_id: usize, context_id: usize) {
        let pos = context_id * COUNT_SOURCE + source_id;
        let group = pos / U32_BITS;
        let index = pos % U32_BITS;

        let ptr = self.enables.0[group].get();
        unsafe { ptr.write_volatile(ptr.read_volatile() | (1 << index)) }
    }

    // /// Disable interrupt `source` in `context`.
    // ///
    // /// See §6.
    // #[inline]
    // pub fn disable(&self, source_id: usize, context_id: usize) {
    //     let pos = context_id * COUNT_SOURCE + source_id;
    //     let group = pos / U32_BITS;
    //     let index = pos % U32_BITS;

    //     let ptr = self.enables.0[group].get();
    //     unsafe { ptr.write_volatile(ptr.read_volatile() & !(1 << index)) }
    // }

    // /// Check if interrupt `source` is enabled in `context`.
    // ///
    // /// See §6.
    // #[inline]
    // pub fn is_enabled(&self, source_id: usize, context_id: usize) -> bool {
    //     let pos = context_id * COUNT_SOURCE + source_id;
    //     let group = pos / U32_BITS;
    //     let index = pos % U32_BITS;

    //     let ptr = self.enables.0[group].get();
    //     (unsafe { ptr.read_volatile() } & (1 << index)) != 0
    // }

    // /// Get interrupt threshold in `context`.
    // ///
    // /// See §7.
    // #[inline]
    // pub fn get_threshold(&self, context_id: usize) -> u32 {
    //     let ptr = self.context_local[context_id].priority_threshold.get();
    //     unsafe { ptr.read_volatile() }
    // }

    /// Set interrupt threshold for `context` to `value`.
    ///
    /// See §7.
    #[inline]
    pub fn set_threshold(&self, context_id: usize, value: u32) {
        let ptr = self.context_local[context_id].priority_threshold.get();
        unsafe { ptr.write_volatile(value) }
    }

    // /// Probe maximum supported threshold value the `context` supports.
    // ///
    // /// See §7.
    // #[inline]
    // pub fn probe_threshold_bits(&self, context_id: usize) -> u32 {
    //     let ptr = self.context_local[context_id].priority_threshold.get();
    //     unsafe {
    //         ptr.write_volatile(!0);
    //         ptr.read_volatile()
    //     }
    // }

    /// Claim an interrupt in `context`, returning its source.
    ///
    /// It is always legal for a hart to perform a claim even if `EIP` is not
    /// set. A hart could set threshold to maximum to disable interrupt
    /// notification, but it does not mean interrupt source has stopped to
    /// send interrupt signals. In this case, hart would instead
    /// poll for active interrupt by periodically calling the `claim` function.
    ///
    /// See §8.
    #[inline]
    pub fn claim(&self, context_id: usize) -> usize {
        let ptr = self.context_local[context_id].claim_or_completion.get();
        unsafe { ptr.read_volatile() as usize }
    }

    /// Mark that interrupt identified by `source` is completed in `context`.
    ///
    /// See §9.
    #[inline]
    pub fn complete(&self, context_id: usize, source_id: usize) {
        let ptr = self.context_local[context_id].claim_or_completion.get();
        unsafe { ptr.write_volatile(source_id as u32) }
    }
}

use defines::{
    error::{errno, KResult},
    signal::{KSignalAction, KSignalSet, Signal, SignalActionFlags, SIGSET_SIZE_BYTES},
};

use crate::{
    hart::local_hart,
    memory::UserCheck,
    process::exit_process,
    signal::{SignalContext, SigprocmaskHow},
};

/// 设置当前**进程**在收到特定信号时的行为
///
/// 参数：
/// - `signum` 指定信号，可以是除了 `SIGKILL` 和 `SIGSTOP` 之外的任意有效信号。见 [`Signal`]
/// - `act` 如果非 NULL，则安装 `act` 指向的新操作
/// - `old_act` 如果非 NULL，则将旧操作写入 `old_act` 中
///
/// 错误：
/// - `EFAULT` 如果 `act` 或者 `old_act` 指向非法地址
/// - `EINVAL` 如果 signum 不是除了 `SIGKILL` 和 `SIGSTOP` 之外的有效信号
pub fn sys_rt_sigaction(
    signum: usize,
    act: UserCheck<KSignalAction>,
    old_act: UserCheck<KSignalAction>,
) -> KResult {
    let Ok(signal) = Signal::try_from(signum as u8) else {
        warn!("use unsupported signal {signum}");
        return Err(errno::EINVAL);
    };
    debug!("read/write {signal:?}'s action");
    if signal == Signal::SIGKILL || signal == Signal::SIGSTOP {
        return Err(errno::EINVAL);
    }
    if !old_act.is_null() {
        let old_act_ptr = unsafe { old_act.check_ptr_mut()? };

        local_hart().curr_process().lock_inner_with(|inner| {
            old_act_ptr.write(inner.signal_handlers.action(signal).clone());
        });
    }

    if !act.is_null() {
        let act = act.check_ptr()?.read();
        if !act.flags.contains(SignalActionFlags::SA_RESTORER) {
            // `SA_RESTORER` 表示传入的 `restore` 字段是有用的
            // 一般而言这个字段由 libc 填写，用于 signal handler 执行结束之后调用 `sys_sigreturn`
            // 如果没有填写，则 os 需要自己手动做一个 trampoline
            todo!("[low] sig trampoline does not impl")
        }
        local_hart().curr_process().lock_inner_with(|inner| {
            inner.signal_handlers.action_mut(signal).clone_from(&act);
        });
    }

    Ok(0)
}

// TODO: 其实 `sys_rt_sigprocmask` 应该只对传统的单线程进程生效，多线程应该使用 `pthread_sigmask`
/// 用于获取或更改**线程**的信号掩码
///
/// 参数：
/// - `how` 指定该调用的行为，具体见 [`SigprocmaskHow`]
/// - `set` 是用户传入的，希望设置的掩码集，具体如何使用取决于 `how`
/// - `old_set` 如果非 NULL，则将旧的信号掩码写入 `old_act` 中
///
/// 错误：
/// - `EFAULT` 如果 `set` 或 `old_set` 指向非法地址
/// - `EINVAL` 如果 `how` 参数非法或者内核不支持 `set_size`
pub fn sys_rt_sigprocmask(
    how: usize,
    set: UserCheck<KSignalSet>,
    old_set: UserCheck<KSignalSet>,
    set_size: usize,
) -> KResult {
    if set_size > SIGSET_SIZE_BYTES {
        return Err(errno::EINVAL);
    }

    if !old_set.is_null() {
        let old_set_ptr = unsafe { old_set.check_ptr_mut()? };

        local_hart().curr_thread().lock_inner_with(|inner| {
            old_set_ptr.write(inner.signal_mask);
        });
    }

    let Ok(how) = SigprocmaskHow::try_from(how) else {
        return Err(errno::EINVAL);
    };

    if !set.is_null() {
        debug!("write signal mask with how = {how:?}");
        let set_ptr = set.check_ptr()?.read();
        local_hart()
            .curr_thread()
            .lock_inner_with(|inner| match how {
                SigprocmaskHow::SIG_BLOCK => inner.signal_mask.insert(set_ptr),
                SigprocmaskHow::SIG_UNBLOCK => inner.signal_mask.remove(set_ptr),
                SigprocmaskHow::SIG_SETMASK => inner.signal_mask = set_ptr,
            });
    }

    Ok(0)
}

pub fn sys_rt_sigreturn() -> KResult {
    debug!("sigreturn called");
    let thread = local_hart().curr_thread();
    let sp = thread.lock_inner_with(|inner| inner.trap_context.sp());
    let Ok(old_ctx) = UserCheck::new(sp as *mut SignalContext).check_ptr() else {
        // TODO:[blocked] 这里其实可以试着补救
        exit_process(&thread.process, -10);
        return Err(errno::BREAK);
    };
    let old_ctx = old_ctx.read();

    thread.lock_inner_with(|inner| {
        inner.signal_mask = old_ctx.old_mask;
        inner.trap_context = old_ctx.old_trap_context;
    });

    Ok(0)
}

use core::time::Duration;

use common::constant::{MICRO_PER_SEC, NANO_PER_SEC};
use defines::{
    error::KResult,
    misc::{TimeSpec, TimeVal, Tms},
};

use crate::{memory::UserCheck, time};

/// 获取自 Epoch 以来所过的时间（不过目前实现中似乎是自开机或复位以来时间）
///
/// 参数：
/// - `ts` 要设置的时间值
/// - `tz` 时区结构，但目前已经过时，不考虑
pub fn sys_get_time_of_day(tv: UserCheck<TimeVal>, _tz: usize) -> KResult {
    // 根据 man 所言，时区参数 `tz` 已经过时了，通常应当是 `NULL`。
    assert_eq!(_tz, 0);
    let tv = unsafe { tv.check_ptr_mut()? };
    let us = riscv_time::get_time_us();
    tv.write(TimeVal {
        sec: us / MICRO_PER_SEC,
        usec: us % MICRO_PER_SEC,
    });
    Ok(0)
}

/// 全局时钟，或者说挂钟
const CLOCK_REALTIME: usize = 0;

/// 同样是获取时间，不过 `TimeSpec` 精度为 ns。
///
/// 可以有不同的时钟，但目前只支持挂钟 (`CLOCK_REALTIME`)。
///
/// 参数：
/// - `clock_id` 时钟 id，目前仅为 `CLOCK_READTIME`
/// - `tp` 指向要设置的用户指针
pub fn sys_clock_gettime(_clock_id: usize, ts: UserCheck<TimeSpec>) -> KResult {
    // TODO: 目前只考虑挂钟时间
    assert_eq!(_clock_id, CLOCK_REALTIME);
    let ts = unsafe { ts.check_ptr_mut()? };
    let us = riscv_time::get_time_ns();
    ts.write(TimeSpec {
        sec: (us / NANO_PER_SEC) as i64,
        nsec: (us % NANO_PER_SEC) as i64,
    });
    Ok(0)
}

// FIXME: `sys_times` 暂时是非正确的实现
/// 获取进程和子进程运行时间，单位是**时钟 tick 数**
///
/// 参数：
/// - `tms` 是一个用户指针，结果被写入其中。
///
/// 错误：
/// - `EFAULT` `tms` 指向非法地址
pub fn sys_times(tms: UserCheck<Tms>) -> KResult {
    let ticks = riscv::register::time::read();
    let tms = unsafe { tms.check_ptr_mut()? };
    tms.write(Tms {
        tms_utime: ticks / 4,
        tms_stime: ticks / 4,
        tms_cutime: ticks / 4,
        tms_cstime: ticks / 4,
    });
    Ok(0)
}

/// 挂起调用线程的执行，直到至少经过 `req` 中指定的时间。成功后返回 0
pub async fn sys_nanosleep(req: UserCheck<TimeSpec>) -> KResult {
    let req = req.check_ptr()?.read();
    let req = Duration::try_from(req)?;
    time::sleep(req).await;
    Ok(0)
}

