#![no_std]

use alloc::vec::Vec;

extern crate alloc;

/// 基于回收的分配器，即用 vector 收集释放的 id
#[derive(Clone)]
pub struct RecycleAllocator {
    current: usize,
    recycled: Vec<usize>,
}

impl Default for RecycleAllocator {
    fn default() -> Self {
        Self::new()
    }
}

impl RecycleAllocator {
    /// 默认从 0 开始分配
    pub const fn new() -> Self {
        RecycleAllocator {
            current: 0,
            recycled: Vec::new(),
        }
    }

    /// 显式决定从哪个数开始分配
    pub const fn begin_with(begin: usize) -> Self {
        RecycleAllocator {
            current: begin,
            recycled: Vec::new(),
        }
    }

    pub fn alloc(&mut self) -> usize {
        if let Some(id) = self.recycled.pop() {
            id
        } else {
            self.current += 1;
            self.current - 1
        }
    }

    pub fn dealloc(&mut self, id: usize) {
        debug_assert!(id < self.current);
        debug_assert!(
            !self.recycled.iter().any(|i| *i == id),
            "id {id} has been deallocated!",
        );
        self.recycled.push(id);
    }

    /// 释放所使用的内存。一般而言，释放之后不应该再使用
    pub fn release(&mut self) {
        self.recycled = Vec::new();
    }
}

# asynclear OS 内核项目深度技术分析报告

## 一、项目概述

**asynclear** 是一个基于 Rust 语言编写的异步操作系统内核，目标架构为 RISC-V 64 (riscv64imac)，运行环境为 QEMU virt 模拟器。项目采用 Rust nightly 工具链（nightly-2024-02-03），使用 cargo workspace 管理多 crate 结构，并采用 xtask 模式进行构建与运行管理。

内核代码总量约 8,493 行（含汇编），工具库约 1,766 行，架构相关代码约 101 行，用户态测试程序约 621 行，构建工具（xtask）约 853 行。

