pub struct LockedHeap<const ORDER: usize>(SpinNoIrqMutex<Heap<ORDER>>);

unsafe impl<const ORDER: usize> GlobalAlloc for LockedHeap<ORDER> {
    unsafe fn alloc(&self, layout: Layout) -> *mut u8 {
