    let (elf_end, auxv, elf_entry) = memory_space.load_elf_sections(&elf, &elf_data)?;

    // 在用户栈上推入参数、环境变量、辅助向量等
    let argc = args.len();
    let (user_sp, argv_base) = memory_space.init_stack(0, args, envs, auxv);

    // ...
}
```

**exec 功能**：
